135	\begin{definition}\leanok
136	[Free-\(k\)-module functor is left adjoint]
137	  \label{def:Scheme_ModuleCat_free_isLeftAdjoint}
138	  \lean{AlgebraicGeometry.Scheme.ModuleCat_free_isLeftAdjoint}
